// ============================================
// SPAM RESCUE - Gmail
// ============================================
// Moving an email from Spam to Inbox is the STRONGEST
// positive signal you can send to Gmail.
//
// In n8n, IMAP doesn't natively support MOVE.
// Options to actually move the email:
//
// Option 1: Use Gmail API node (recommended)
//   - Remove SPAM label, add INBOX label
//   - Gmail API > Modify Message > removeLabelIds: ['SPAM'], addLabelIds: ['INBOX']
//
// Option 2: Use HTTP Request node to Gmail API
//   - POST https://gmail.googleapis.com/gmail/v1/users/me/messages/{id}/modify
//   - Body: { removeLabelIds: ['SPAM'], addLabelIds: ['INBOX'] }
//
// For now, this node logs the rescue action.
// Connect a Gmail API node after this for actual MOVE.

const emailData = $input.first().json;

return [{
  json: {
    action: 'rescue_from_spam',
    provider: 'gmail',
    from: emailData.from,
    subject: emailData.subject || '(no subject)',
    messageId: emailData.messageId || '',
    spamFolder: '[Gmail]/Spam',
    rescuedAt: new Date().toISOString(),
    instruction: 'Connect Gmail API node to move: removeLabelIds SPAM, addLabelIds INBOX'
  }
}];

// ============================================
// SPAM RESCUE - Outlook
// ============================================
// Moving from Junk to Inbox trains Outlook that
// this sender is legitimate.
//
// For Outlook/Microsoft 365:
// Use Microsoft Graph API to move message:
//   POST /me/messages/{id}/move
//   Body: { destinationId: 'inbox' }
//
// For now, this node logs the rescue action.
// Connect a Microsoft Graph API node after this.

const emailData = $input.first().json;

return [{
  json: {
    action: 'rescue_from_spam',
    provider: 'outlook',
    from: emailData.from,
    subject: emailData.subject || '(no subject)',
    messageId: emailData.messageId || '',
    spamFolder: 'Junk',
    rescuedAt: new Date().toISOString(),
    instruction: 'Connect Microsoft Graph API node to move message to Inbox'
  }
}];

// Consolidated rescue log
// Track all spam rescues for monitoring warmup health

const data = $input.first().json;

// If too many emails landing in spam, it indicates:
// 1. DNS records (SPF/DKIM/DMARC) may be misconfigured
// 2. Sending volume ramped too fast
// 3. Email content may be triggering filters

return [{
  json: {
    ...data,
    status: 'rescued_successfully',
    healthNote: 'If spam rate > 5%, slow down sending volume and check DNS records'
  }
}];
